// In production: call GET https://api.openai.com/v1/usage to get real usage data
// Sample week of AI cost data across workflows
const usage_data = [
  { workflow: '72-survey-response-analyser', model: 'gpt-4o-mini', input_tokens: 45200, output_tokens: 12800, calls: 34, period: 'week' },
  { workflow: '78-synthesis-report-builder', model: 'gpt-4o', input_tokens: 38000, output_tokens: 22000, calls: 8, period: 'week' },
  { workflow: '81-bug-triage-assistant', model: 'gpt-4o-mini', input_tokens: 18600, output_tokens: 5400, calls: 42, period: 'week' },
  { workflow: '74-persona-generator', model: 'gpt-4o', input_tokens: 22000, output_tokens: 14000, calls: 6, period: 'week' }
];
const budget_config = {
  weekly_budget_usd: 25.00,
  alert_threshold_pct: 80,
  per_workflow_budget_usd: 10.00
};
const pricing = { 'gpt-4o-mini': { input: 0.000150, output: 0.000600 }, 'gpt-4o': { input: 0.005, output: 0.015 } }; // per 1k tokens
return [{ json: { usage_data, budget_config, pricing, period: 'week', period_start: '2026-07-07', period_end: '2026-07-13' } }];

const { usage_data, budget_config, pricing, period_start, period_end } = $input.first().json;
const per_workflow = usage_data.map(u => {
  const p = pricing[u.model] || { input: 0.001, output: 0.002 };
  const cost = (u.input_tokens / 1000 * p.input) + (u.output_tokens / 1000 * p.output);
  const over_budget = cost > budget_config.per_workflow_budget_usd;
  return { ...u, cost_usd: parseFloat(cost.toFixed(4)), over_budget };
});
const total_cost = per_workflow.reduce((s,w) => s + w.cost_usd, 0);
const budget_pct = (total_cost / budget_config.weekly_budget_usd) * 100;
const alert = budget_pct >= budget_config.alert_threshold_pct;
const model_totals = {};
per_workflow.forEach(w => { model_totals[w.model] = (model_totals[w.model] || 0) + w.cost_usd; });
const sorted = [...per_workflow].sort((a,b) => b.cost_usd - a.cost_usd);
return [{ json: { per_workflow: sorted, model_totals, total_cost: parseFloat(total_cost.toFixed(4)), budget_config, budget_pct: parseFloat(budget_pct.toFixed(1)), alert, period: { start: period_start, end: period_end }, generated_at: new Date().toISOString() } }];

const d = $input.first().json;
const wfLines = d.per_workflow.map(w => `  ${w.over_budget?'⚠️':'  '} ${w.workflow} [${w.model}]: $${w.cost_usd} (${w.calls} calls, ${(w.input_tokens+w.output_tokens).toLocaleString()} tokens)${w.over_budget?' OVER BUDGET':''}`).join('\n');
const modelLines = Object.entries(d.model_totals).map(([m,c])=>`  ${m}: $${c.toFixed(4)}`).join('\n');
const report = [
  `AI COST REPORT: ${d.period.start} → ${d.period.end}`,
  `Generated: ${d.generated_at}`,
  ``,
  `TOTAL COST: $${d.total_cost} / $${d.budget_config.weekly_budget_usd} weekly budget (${d.budget_pct}%)${d.alert ? ' ⚠️ ALERT: above '+d.budget_config.alert_threshold_pct+'% threshold' : ''}`,
  ``,
  `BY WORKFLOW (highest cost first):`,
  wfLines,
  ``,
  `BY MODEL:`,
  modelLines,
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
